//! # K-quant row dequantization — real weight tiles for the τ-bowl gate.
//!
//! `bowl-probe` could only analyse Q8_0/F16/F32 tensors; the FFN weights of real
//! models are **Q6_K / Q5_0** (the layers where outlier features live). This
//! module exposes pure per-row dequantizers for those formats so the gate can be
//! run on real FFN tiles, not just the embedding.
//!
//! ## Why this is safe (no format-misread)
//!
//! Each dequantizer mirrors the crate's own tested reference kernel block layout
//! (`model.rs` `mat_vec_q{8_0,5_0,6k}_reference`) VERBATIM, and each is
//! **verified against the public, tested `mat_vec_dispatch_batch`**: for random
//! bytes, `dequantize_row(w, i) · x` must equal `mat_vec_dispatch_batch(QType, w)
//! [i]` to f32 tolerance. A wrong layout fails that test — it cannot ship a
//! garbage-but-plausible number (the Sardis failure this project guards against).
//!
//! Block layouts (GGUF):
//!   * Q8_0 : 34 B/block of 32 = `[f16 d][32 × i8]`, w = d·q
//!   * Q5_0 : 22 B/block of 32 = `[f16 d][u32 qh][16 × (lo4|lo4)]`, w = d·((q4|qh_bit)−16)
//!   * Q6_K : 210 B/block of 256 = `[128 ql][64 qh][16 i8 scales][f16 d]`,
//!            w = d · scale · (q6 − 32)

#![allow(dead_code)]

/// Standard IEEE-754 half → f32 (block scales are stored as f16).
#[inline]
pub fn f16_to_f32(h: u16) -> f32 {
    let sign = (h >> 15) & 1;
    let exp = (h >> 10) & 0x1f;
    let mant = h & 0x3ff;
    let val = if exp == 0 {
        (mant as f32) * 2f32.powi(-24)
    } else if exp == 0x1f {
        if mant == 0 { f32::INFINITY } else { f32::NAN }
    } else {
        (1.0 + mant as f32 / 1024.0) * 2f32.powi(exp as i32 - 15)
    };
    if sign == 1 { -val } else { val }
}

/// Dequantize row `row` (length `cols`) of a Q8_0 tensor into `out`.
pub fn dequantize_q8_0_row(out: &mut [f32], w: &[u8], row: usize, cols: usize) {
    let blocks = cols.div_ceil(32);
    let row_start = row * blocks * 34;
    for block in 0..blocks {
        let bs = row_start + block * 34;
        let d = f16_to_f32(u16::from_le_bytes([w[bs], w[bs + 1]]));
        let xo = block * 32;
        for j in 0..32 {
            let idx = xo + j;
            if idx < cols {
                out[idx] = (w[bs + 2 + j] as i8) as f32 * d;
            }
        }
    }
}

/// Dequantize row `row` (length `cols`) of a Q5_0 tensor into `out`.
pub fn dequantize_q5_0_row(out: &mut [f32], w: &[u8], row: usize, cols: usize) {
    let blocks = cols.div_ceil(32);
    let row_start = row * blocks * 22;
    for block in 0..blocks {
        let bs = row_start + block * 22;
        let d = f16_to_f32(u16::from_le_bytes([w[bs], w[bs + 1]]));
        let qh = (w[bs + 2] as u32)
            | ((w[bs + 3] as u32) << 8)
            | ((w[bs + 4] as u32) << 16)
            | ((w[bs + 5] as u32) << 24);
        let xo = block * 32;
        for j in 0..16 {
            let idx0 = xo + j;
            let idx1 = xo + j + 16;
            let xh0 = (((qh >> j) << 4) & 0x10) as i32;
            let xh1 = (((qh >> (j + 16)) << 4) & 0x10) as i32;
            let q = w[bs + 6 + j];
            if idx0 < cols {
                out[idx0] = (((q & 0x0f) as i32 | xh0) - 16) as f32 * d;
            }
            if idx1 < cols {
                out[idx1] = (((q >> 4) as i32 | xh1) - 16) as f32 * d;
            }
        }
    }
}

/// Dequantize row `row` of a Q6_K tensor into `out`. `cols` must be a multiple
/// of 256 (the Q6_K super-block size); returns silently leaving `out` untouched
/// past the last whole block otherwise.
pub fn dequantize_q6k_row(out: &mut [f32], w: &[u8], row: usize, cols: usize) {
    let blocks = cols / 256;
    let row_start = row * blocks * 210;
    for block in 0..blocks {
        let bs = row_start + block * 210;
        let d = f16_to_f32(u16::from_le_bytes([w[bs + 208], w[bs + 209]]));
        let xo = block * 256;
        for group in 0..2 {
            let ns = group * 128;
            let ql = bs + group * 64;
            let qh = bs + 128 + group * 32;
            let sc = bs + 192 + group * 8;
            for l in 0..32 {
                let qhv = w[qh + l] as i32;
                let ql1 = w[ql + l] as i32;
                let ql2 = w[ql + l + 32] as i32;
                let q1 = ((ql1 & 0xF) | ((qhv & 3) << 4)) - 32;
                let q2 = ((ql2 & 0xF) | (((qhv >> 2) & 3) << 4)) - 32;
                let q3 = ((ql1 >> 4) | (((qhv >> 4) & 3) << 4)) - 32;
                let q4 = ((ql2 >> 4) | (((qhv >> 6) & 3) << 4)) - 32;
                let is = l >> 4;
                let s0 = w[sc + is] as i8 as f32;
                let s1 = w[sc + is + 2] as i8 as f32;
                let s2 = w[sc + is + 4] as i8 as f32;
                let s3 = w[sc + is + 6] as i8 as f32;
                out[xo + ns + l] = d * s0 * q1 as f32;
                out[xo + ns + l + 32] = d * s1 * q2 as f32;
                out[xo + ns + l + 64] = d * s2 * q3 as f32;
                out[xo + ns + l + 96] = d * s3 * q4 as f32;
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::e8_quantizer::SplitMix64;
    use crate::model::{mat_vec_dispatch_batch, QType};

    fn rand_bytes(n: usize, seed: u64) -> Vec<u8> {
        let mut r = SplitMix64::new(seed);
        (0..n).map(|_| (((r.next_in(1.0) + 1.0) * 127.5) as i32 & 0xff) as u8).collect()
    }
    fn rand_x(n: usize, seed: u64) -> Vec<f32> {
        let mut r = SplitMix64::new(seed);
        (0..n).map(|_| r.next_in(1.0) as f32).collect()
    }

    /// Verify a row-dequantizer against the crate's public tested kernel:
    /// `dequant_row(i) · x` must equal `mat_vec_dispatch_batch(...)[i]`.
    fn verify(
        qtype: QType,
        bytes_per_block: usize,
        elems_per_block: usize,
        rows: usize,
        cols: usize,
        dequant: impl Fn(&mut [f32], &[u8], usize, usize),
        seed: u64,
    ) {
        let blocks_per_row = cols / elems_per_block;
        let w = rand_bytes(rows * blocks_per_row * bytes_per_block, seed);
        let x = rand_x(cols, seed ^ 0xABCD);
        let mut expect = vec![0.0f32; rows];
        mat_vec_dispatch_batch(&mut expect, &x, &w, qtype, rows, cols, 1, rows);
        let mut row = vec![0.0f32; cols];
        let mut max_err = 0.0f32;
        for i in 0..rows {
            for v in row.iter_mut() {
                *v = 0.0;
            }
            dequant(&mut row, &w, i, cols);
            let dot: f32 = row.iter().zip(&x).map(|(a, b)| a * b).sum();
            max_err = max_err.max((dot - expect[i]).abs());
        }
        let scale = expect.iter().fold(0.0f32, |m, v| m.max(v.abs())).max(1.0);
        assert!(
            max_err / scale < 1e-4,
            "{qtype:?}: row-dequant·x disagrees with mat_vec (max_err {max_err}, scale {scale})"
        );
    }

    #[test]
    fn q8_0_row_matches_kernel() {
        verify(QType::Q8_0, 34, 32, 12, 256, dequantize_q8_0_row, 0x00C8);
    }

    #[test]
    fn q5_0_row_matches_kernel() {
        verify(QType::Q5_0, 22, 32, 12, 256, dequantize_q5_0_row, 0x50 ^ 7);
    }

    #[test]
    fn q6k_row_matches_kernel() {
        verify(QType::Q6K, 210, 256, 8, 512, dequantize_q6k_row, 0x6C ^ 3);
    }

    /// q4k was the one mixed-precision layer matvec lacking this guard while it
    /// got a new simd128 wasm path. `mat_vec_dispatch_batch(Q4K)` (→ the same
    /// mat_vec_q4k_row_batch the wasm SIMD path lives in) must agree with an
    /// independent `dequantize_q4k_row·x` — certifies the shared q4k block layout
    /// (144B: fp16 d/dmin + 12 scale bytes + 128 nibble bytes; get_scale_min_k4)
    /// that ALL arch paths (NEON / scalar / wasm-simd) depend on. Block = 144B,
    /// 256 elems. (The wasm-simd codegen itself is certified E2E by the multi-token
    /// qspec golden — no in-crate wasm runtime.)
    #[test]
    fn q4k_row_matches_kernel() {
        verify(QType::Q4K, 144, 256, 8, 512, crate::math::dequantize_q4k_row, 0x4B ^ 5);
    }

    /// q5k was the LAST quant lacking this guard (q4k/q5_0/q6k/q8_0 all have it).
    /// Its kernel path differs — `mat_vec_q5k_batch` dequantizes a full row then
    /// `dot_product`s it (vs the fused per-arch row kernels) — so this checks that
    /// `dot_product` agrees with the independent `dequantize_q5k_row · x` reference
    /// @1e-4. Q5_K block = 176 B, 256 elems. Completes parity coverage for all five
    /// quant types the dispatch serves.
    #[test]
    fn q5k_row_matches_kernel() {
        verify(QType::Q5K, 176, 256, 8, 512, crate::math::dequantize_q5k_row, 0x5C ^ 9);
    }
}
